Here's a simple solution: holding down the Ctrl key can simulate holding down the mouse button.
There are two ways to apply this solution:

1. Manually paste the code into the browser's DevTools console.

2. Use a browser extension that allows code injection and paste the code there.

```js
let [x, y] = [0, 0];
const canvas = document.querySelector("canvas.excalidraw__canvas.interactive");
window.addEventListener("pointermove", e => void ([x, y] = [e.x, e.y]));
window.addEventListener("keydown", e => {
  if (!e.ctrlKey) return
  // start
  canvas.dispatchEvent(new PointerEvent('pointerdown', { clientX: x, clientY: y, bubbles: true, pointerType: 'mouse', pointerId: 1 }));
  // over
  window.addEventListener("keyup", () => canvas.dispatchEvent(new PointerEvent('pointerup', { clientX: x, clientY: y, bubbles: true, pointerType: 'mouse', pointerId: 1 })), { once: true })
});
```

